from dataclasses import dataclass, field
from datetime import date, timedelta
from collections import defaultdict

@dataclass
class UsageEvent:
    user_id: str
    event_date: date
    tool: str
    is_tutorial: bool  # exclude tutorial/onboarding sessions

@dataclass
class StickinessCalculator:
    events: list[UsageEvent]

    def _active_users_in_window(self, end_date: date, days: int) -> set[str]:
        start = end_date - timedelta(days=days - 1)
        return {
            e.user_id for e in self.events
            if start <= e.event_date <= end_date and not e.is_tutorial
        }

    def dau_mau_ratio(self, on_date: date) -> float:
        """Stickiness for a single day: |DAU| / |MAU(last 30 days)|."""
        dau = self._active_users_in_window(on_date, 1)
        mau = self._active_users_in_window(on_date, 30)
        if not mau:
            return 0.0
        return len(dau) / len(mau)

    def monthly_avg_stickiness(self, year: int, month: int) -> float:
        """Average daily DAU/MAU ratio across all days in the given month."""
        from calendar import monthrange
        _, days_in_month = monthrange(year, month)
        ratios = []
        for day in range(1, days_in_month + 1):
            d = date(year, month, day)
            ratio = self.dau_mau_ratio(d)
            if ratio > 0:
                ratios.append(ratio)
        return sum(ratios) / len(ratios) if ratios else 0.0

    def stickiness_trend(self, start_date: date, months: int) -> list[dict]:
        """Returns monthly stickiness for each of `months` months starting at start_date."""
        results = []
        y, m = start_date.year, start_date.month
        for _ in range(months):
            avg = self.monthly_avg_stickiness(y, m)
            results.append({"year": y, "month": m, "dau_mau": avg})
            m += 1
            if m > 12:
                m = 1
                y += 1
        return results

# Usage
calc = StickinessCalculator(events=[])  # populate from platform telemetry
trend = calc.stickiness_trend(date(2025, 1, 1), months=6)
for t in trend:
    print(f"{t['year']}-{t['month']:02d}: {t['dau_mau']:.1%}")

from dataclasses import dataclass
from datetime import date
from typing import Optional

@dataclass
class CohortRecord:
    user_id: str
    cohort_month: str           # e.g. "2025-01" — first month of real tool use
    business_unit: str
    role: str
    # Monthly active flags (True = at least one real session that month)
    monthly_active: dict[str, bool] = None  # keys: "2025-01", "2025-02", ...

    def __post_init__(self):
        if self.monthly_active is None:
            self.monthly_active = {}

    def retention_at_month_n(self, n: int) -> bool:
        """Was this user active in month N after their cohort month?"""
        from datetime import date
        y, m = int(self.cohort_month[:4]), int(self.cohort_month[5:])
        m += n
        while m > 12:
            m -= 12
            y += 1
        key = f"{y:04d}-{m:02d}"
        return self.monthly_active.get(key, False)

@dataclass
class CohortRetentionTable:
    cohorts: dict[str, list[CohortRecord]]  # key: cohort_month

    def retention_curve(self, cohort_month: str, max_months: int = 6) -> list[float]:
        records = self.cohorts.get(cohort_month, [])
        if not records:
            return []
        return [
            sum(1 for r in records if r.retention_at_month_n(n)) / len(records)
            for n in range(max_months + 1)
        ]

    def compare_cohorts(self, months: list[str], at_month_n: int = 3) -> dict[str, float]:
        """Compare M3 retention across cohorts to see if onboarding improvements worked."""
        return {
            cm: (self.retention_curve(cm, at_month_n)[at_month_n]
                 if len(self.retention_curve(cm, at_month_n)) > at_month_n else 0.0)
            for cm in months
        }

# Example usage
