from dataclasses import dataclass, field
from datetime import datetime
from statistics import median
from typing import Optional

@dataclass
class SessionRecord:
    session_id: str
    user_id: str
    start_time: datetime
    end_time: datetime
    turns: int                  # prompt-response pairs in the session
    output_utilised: bool       # was output copied/exported?
    avg_prompt_length: int      # characters
    is_tutorial: bool

    def duration_minutes(self) -> float:
        return (self.end_time - self.start_time).total_seconds() / 60

@dataclass
class EngagementDepthAnalyser:
    sessions: list[SessionRecord]

    def _real_sessions(self) -> list[SessionRecord]:
        return [s for s in self.sessions if not s.is_tutorial]

    def median_duration_minutes(self) -> float:
        durations = [s.duration_minutes() for s in self._real_sessions()]
        return median(durations) if durations else 0.0

    def median_turns_per_session(self) -> float:
        turns = [s.turns for s in self._real_sessions()]
        return median(turns) if turns else 0.0

    def output_utilisation_rate(self) -> float:
        real = self._real_sessions()
        if not real:
            return 0.0
        return sum(1 for s in real if s.output_utilised) / len(real)

    def avg_prompt_length_trend(self, by_month: bool = True) -> dict[str, float]:
        """Average prompt length per month — rising trend indicates skill growth."""
        by_m: dict[str, list[int]] = {}
        for s in self._real_sessions():
            key = s.start_time.strftime("%Y-%m")
            by_m.setdefault(key, []).append(s.avg_prompt_length)
        return {k: sum(v)/len(v) for k, v in sorted(by_m.items())}

    def depth_summary(self) -> dict:
        return {
            "median_duration_min":     round(self.median_duration_minutes(), 1),
            "median_turns":            round(self.median_turns_per_session(), 1),
            "output_utilisation_pct":  round(self.output_utilisation_rate() * 100, 1),
            "prompt_length_trend":     self.avg_prompt_length_trend(),
        }

analyser = EngagementDepthAnalyser(sessions=[])
print(analyser.depth_summary())
